function BBF.ApplyProfile(profileName)
    local profile
    for _, p in ipairs(BBF.ProfileData) do
        if p.name == profileName then
            profile = p
            break
        end
    end
    if not profile then
        BBF.Print("Profile not found: " .. tostring(profileName))
        return
    end

    local profileData, errorMessage = BBF.OldImportProfile(profile.importString, "fullProfile")
    if errorMessage then
        BBF.Print(L["Print_Error_Importing_Profile"] .. " " .. tostring(errorMessage))
    else
        for k in pairs(BetterBlizzFramesDB) do BetterBlizzFramesDB[k] = nil end
        for k, v in pairs(profileData) do
            BetterBlizzFramesDB[k] = v
        end
        BetterBlizzFramesDB.skipUpdateMsg = true
        ReloadUI()
    end
end
